package org.eclipse.rdf4j.sail.lmdb.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTimeoutPreemptively;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.lang.foreign.MemorySegment;
import java.time.Duration;
import java.util.List;

import org.eclipse.rdf4j.sail.lmdb.sketch.omni.CompactOmniSketch;
import org.eclipse.rdf4j.sail.lmdb.sketch.omni.OmniSketch;
import org.eclipse.rdf4j.sail.lmdb.sketch.omni.OmniSketchEstimate;
import org.eclipse.rdf4j.sail.lmdb.sketch.omni.OmniSketchPredicate;
import org.eclipse.rdf4j.sail.lmdb.sketch.omni.OmniSketches;
import org.eclipse.rdf4j.sail.lmdb.sketch.omni.UpdateOmniSketch;
import org.junit.jupiter.api.Test;

class OmniSketchCoreTest {

	@Test
	void zipOmniPackageIsVendored() {
		UpdateOmniSketch sketch = newSketch(16, 2, 16);

		assertEquals("OMNI", sketch.getFamily().getFamilyName());
	}

	@Test
	void pointInAndNullPredicatesFollowZipApi() {
		UpdateOmniSketch sketch = newSketch(128, 4, 64);
		for (int i = 0; i < 1_000; i++) {
			sketch.update(i % 10, i);
		}
		for (int i = 1_000; i < 1_100; i++) {
			sketch.updateNull(i);
		}

		assertFalse(sketch.isEmpty());
		assertBetween(70.0d, 130.0d, sketch.getEstimate(3L));

		OmniSketchEstimate inEstimate = sketch.estimate(OmniSketchPredicate.anyOfLongs(1L, 2L));
		OmniSketchEstimate nullEstimate = sketch.estimate(OmniSketchPredicate.isNull());

		assertBetween(150.0d, 250.0d, inEstimate.getEstimate());
		assertBetween(80.0d, 120.0d, nullEstimate.getEstimate());
	}

	@Test
	void intersectionAcrossDimensionsFollowsZipApi() {
		UpdateOmniSketch country = newSketch(128, 4, 128);
		UpdateOmniSketch browser = newSketch(128, 4, 128);
		for (int user = 0; user < 2_000; user++) {
			country.update(user % 2 == 0 ? "NO" : "SE", user);
			browser.update(user % 4 == 0 ? "Firefox" : "Chrome", user);
		}

		OmniSketchEstimate estimate = OmniSketches.intersection(
				List.of(country, browser),
				List.of(OmniSketchPredicate.equalTo("NO"), OmniSketchPredicate.equalTo("Firefox")));

		assertBetween(400.0d, 600.0d, estimate.getEstimate());
	}

	@Test
	void compactSerializationHeapifiesAndWrapsZipImages() {
		UpdateOmniSketch sketch = newSketch(64, 3, 32);
		for (int i = 0; i < 300; i++) {
			sketch.update(i % 6, i);
		}
		CompactOmniSketch compact = sketch.compact();
		byte[] bytes = compact.toByteArray();
		assertEquals(bytes.length, compact.getCompactBytes());

		CompactOmniSketch heapified = OmniSketch.heapify(bytes);
		CompactOmniSketch wrapped = OmniSketch.wrap(MemorySegment.ofArray(bytes));

		assertEquals(sketch.getTotalUpdates(), heapified.getTotalUpdates());
		assertEquals(sketch.getEstimate(2L), heapified.getEstimate(2L));
		assertEquals(sketch.getEstimate(2L), wrapped.getEstimate(2L));
		assertTrue(wrapped.hasMemorySegment());
	}

	@Test
	void directRetainedMembershipMatchesProbeAcrossHeapAndCompactSketches() {
		UpdateOmniSketch sketch = newSketch(64, 4, 32);
		long valueHash = OmniJoinEstimator.stableHash("direct-membership-value");
		long[] identifiers = new long[300];
		for (int i = 0; i < identifiers.length; i++) {
			identifiers[i] = OmniJoinEstimator.stableHash("direct-membership-id:" + i);
			sketch.updateHash(valueHash, identifiers[i]);
		}
		long[] retained = sketch.probeHash(valueHash).getIdentifierHashes();
		CompactOmniSketch compact = sketch.compact();

		for (long identifier : identifiers) {
			boolean expected = contains(retained, identifier);
			assertEquals(expected, sketch.isIdentifierHashRetained(valueHash, identifier));
			assertEquals(expected, compact.isIdentifierHashRetained(valueHash, identifier));
		}
	}

	@Test
	void probeJoinPreservesZeroRetainedSampleLoss() {
		OmniJoinEstimator estimator = new OmniJoinEstimator(64, 3, 64, 1L);
		OmniWitnessSet input = OmniWitnessSet.fromSortedUnsigned(new long[0], new double[0], 0,
				0.125d, 0.25d, OmniWitnessSet.FallbackReason.SAMPLE_LOSS, 8.0d);

		OmniWitnessSet output = estimator.probeJoinStaticRetainedAtMost(input,
				estimator.relation(OmniRelation.STATEMENT), OmniAttributeRef.component(0),
				OmniJoinEstimator.OutputIdentifier.RECORD, 16);

		assertEquals(OmniWitnessSet.FallbackReason.SAMPLE_LOSS, output.fallbackReason());
		assertEquals(8.0d, output.estimatedRows(), 0.0d);
		assertFalse(output.isEmpty());
	}

	@Test
	void unionMergesPartitionsFollowingZipApi() {
		var builder = OmniSketch.builder().setWidth(64).setNumRows(3).setNominalEntries(64);
		UpdateOmniSketch left = builder.build();
		UpdateOmniSketch right = builder.build();
		for (int i = 0; i < 500; i++) {
			left.update(i % 5, i);
		}
		for (int i = 500; i < 1_000; i++) {
			right.update(i % 5, i);
		}

		var union = builder.buildUnion();
		union.update(left);
		union.update(right.compact());
		CompactOmniSketch result = union.getResult();

		assertEquals(1_000L, result.getTotalUpdates());
		assertBetween(150.0d, 250.0d, result.getEstimate(3L));
	}

	@Test
	void duplicateUpdatesDoNotInflateDistinctEstimate() {
		UpdateOmniSketch sketch = newSketch(128, 4, 64);
		for (int i = 0; i < 500; i++) {
			sketch.update(i % 5, i);
			sketch.update(i % 5, i);
		}

		assertBetween(70.0d, 130.0d, sketch.getEstimate(3L));
	}

	@Test
	void kmvDistinctEstimateSurvivesDuplicatesAndSerialization() {
		UpdateOmniSketch sketch = newSketch(128, 4, 64);
		for (int i = 0; i < 10_000; i++) {
			sketch.update(7L, i);
			sketch.update(7L, i);
		}

		double live = sketch.getEstimate(7L);
		assertBetween(7_000.0d, 13_000.0d, live);

		byte[] bytes = sketch.compact().toByteArray();
		assertEquals(live, OmniSketch.heapify(bytes).getEstimate(7L), 0.0d);
		assertEquals(live, OmniSketch.wrap(MemorySegment.ofArray(bytes)).getEstimate(7L), 0.0d);
	}

	@Test
	void duplicateInPredicateValuesDoNotInflateEstimate() {
		UpdateOmniSketch sketch = newSketch(128, 4, 64);
		for (int i = 0; i < 1_000; i++) {
			sketch.update(i % 10, i);
		}

		double deduplicated = sketch.estimate(OmniSketchPredicate.anyOfLongs(1L, 2L)).getEstimate();

		assertEquals(deduplicated,
				sketch.estimate(OmniSketchPredicate.anyOfLongs(1L, 1L, 2L, 2L)).getEstimate(), 0.0d);
		assertEquals(deduplicated,
				sketch.estimate(OmniSketchPredicate.in(List.of(1L, 1L, 2L, 2L))).getEstimate(), 0.0d);
	}

	@Test
	void duplicateStringAndHashPredicateValuesDoNotInflateEstimate() {
		UpdateOmniSketch sketch = newSketch(128, 4, 64);
		for (int i = 0; i < 1_000; i++) {
			sketch.update(i % 2 == 0 ? "even" : "odd", i);
		}

		assertEquals(sketch.estimate(OmniSketchPredicate.anyOfStrings("even")).getEstimate(),
				sketch.estimate(OmniSketchPredicate.anyOfStrings("even", "even")).getEstimate(), 0.0d);
	}

	@Test
	void inPredicateFactoriesDeduplicateValues() {
		assertEquals(2, OmniSketchPredicate.in(List.of("a", "a", "b")).size());
		assertEquals(2, OmniSketchPredicate.anyOfLongs(1L, 1L, 2L).size());
		assertEquals(1, OmniSketchPredicate.anyOfStrings("even", "even").size());
		assertEquals(1, OmniSketchPredicate.anyOfHashes(42L, 42L).size());
	}

	@Test
	void longRangeEndingAtMaxValueTerminates() {
		OmniSketchPredicate predicate = assertTimeoutPreemptively(Duration.ofSeconds(2),
				() -> OmniSketchPredicate.longRange(Long.MAX_VALUE - 5L, Long.MAX_VALUE));

		assertEquals(6, predicate.size());
	}

	private static UpdateOmniSketch newSketch(int width, int rows, int nominalEntries) {
		return OmniSketch.builder()
				.setWidth(width)
				.setNumRows(rows)
				.setNominalEntries(nominalEntries)
				.build();
	}

	private static boolean contains(long[] values, long expected) {
		for (long value : values) {
			if (value == expected) {
				return true;
			}
		}
		return false;
	}

	private static void assertBetween(double lowerExclusive, double upperExclusive, double value) {
		assertTrue(value > lowerExclusive, "estimate=" + value);
		assertTrue(value < upperExclusive, "estimate=" + value);
	}
}
